class AsyncIteratorReadAheadTest {

	@Test
	void depthOneReadsOneElementPerBatchInCallerThread() {
		CountingIteration source = new CountingIteration(bindingSets(3));
		try (var iteration = new AsyncIteratorReadAhead(source, 1)) {
			assertTrue(iteration.hasNext());
			assertEquals(1, source.nextCount.get());
			iteration.next();

			assertTrue(iteration.hasNext());
			assertEquals(2, source.nextCount.get());
			iteration.next();
		}
	}

	@Test
	void depthThreeBuffersBatchBeforeConsumption() {
		CountingIteration source = new CountingIteration(bindingSets(5));
		try (var iteration = new AsyncIteratorReadAhead(source, 3)) {
			assertTrue(iteration.hasNext());
			assertEquals(3, source.nextCount.get());

			iteration.next();
			iteration.next();
			iteration.next();
			assertEquals(3, source.nextCount.get());

			assertTrue(iteration.hasNext());
			assertEquals(5, source.nextCount.get());
		}
	}

	@Test
	void closeClosesUnderlyingIteration() {
		CountingIteration source = new CountingIteration(bindingSets(2));
		AsyncIteratorReadAhead iteration = new AsyncIteratorReadAhead(source, 2);
		assertTrue(iteration.hasNext());
		iteration.close();
		assertTrue(source.closed.get());
		assertFalse(iteration.hasNext());
	}

	@Test
	void positiveDepthWrapsPreparedStepWithoutExecutorAndCreatesInCallerThread() {
		AtomicReference<String> createdOnThread = new AtomicReference<>();
		QueryEvaluationStep prepared = bindings -> {
			createdOnThread.set(Thread.currentThread().getName());
			return new CountingIteration(bindingSets(1));
		};
		QueryEvaluationContext context = new QueryEvaluationContext.Minimal(null) {
			@Override
			public int getJoinReadAheadDepth() {
				return 1;
			}
		};

		try (CloseableIteration<BindingSet> iteration = AsyncIteratorReadAhead
				.getInstance(prepared, EmptyBindingSet.getInstance(), context)) {
			assertTrue(iteration instanceof AsyncIteratorReadAhead);
			assertTrue(iteration.hasNext());
			iteration.next();
		}
		assertEquals(Thread.currentThread().getName(), createdOnThread.get());
	}

	@Test
	void depthZeroReturnsOriginalIteration() {
		CountingIteration source = new CountingIteration(bindingSets(1));
		assertSame(source, AsyncIteratorReadAhead.getInstance(source, 0));
	}

	private static List<BindingSet> bindingSets(int count) {
		List<BindingSet> values = new ArrayList<>(count);
		for (int i = 0; i < count; i++) {
			QueryBindingSet bindingSet = new QueryBindingSet();
			bindingSet.addBinding("x", SimpleValueFactory.getInstance().createLiteral(i));
			values.add(bindingSet);
		}
		return values;
	}

	private static final class CountingIteration implements CloseableIteration<BindingSet> {
		private final List<BindingSet> values;
		private final AtomicInteger nextCount = new AtomicInteger();
		private final AtomicBoolean closed = new AtomicBoolean();
		private int index;

		private CountingIteration(List<BindingSet> values) {
			this.values = values;
		}

		@Override
		public boolean hasNext() {
			return index < values.size();
		}

		@Override
		public BindingSet next() {
			nextCount.incrementAndGet();
			return values.get(index++);
		}

		@Override
		public void close() {
			closed.set(true);
		}
	}
}
